+│   │   │       │   ├── Tooltip/
+│   │   │       │   │   ├── Tooltip.tsx
+│   │   │       │   │   ├── Tooltip.module.css
+│   │   │       │   │   └── index.ts
+│   │   │       │   └── Popover/
+│   │   │       │       ├── Popover.tsx
+│   │   │       │       ├── Popover.module.css
+│   │   │       │       └── index.ts
+│   │   │       └── Molecules/                    # Composed of atoms; has product-domain knowledge
+│   │   │           └── RecommendationsProductCard/
+│   │   │               ├── RecommendationsProductCard.tsx
+│   │   │               ├── RecommendationsProductCard.module.css
+│   │   │               └── index.ts
+```
+
+**Public exports (`index.ts`):**
+
+```ts
+// packages/react/src/widgets/RecommendationsWidgets/TrendingProductsWidget/index.ts
+export { TrendingProductsWidget } from './TrendingProductsWidget';
+export { useTrendingProducts } from './useTrendingProducts';
+export type {
+  TrendingProduct,
+  TrendingProductsWidgetProps,
+} from './types';
+
+// Atoms and Molecules are NOT exported from the widget's public index during the fast-track phase.
+// They are accessible via deep import for internal widget use only:
+// import { FavoriteButton } from '.../Atoms/FavoriteButton';
+// import { RecommendationsProductCard } from '.../Molecules/RecommendationsProductCard';
+```
+
+The widget is re-exported from the main package index:
+
+```ts
+// packages/react/src/index.ts
+export { TrendingProductsWidget, useTrendingProducts } from './widgets/RecommendationsWidgets/TrendingProductsWidget';
+export type { TrendingProduct, TrendingProductsWidgetProps } from './widgets/RecommendationsWidgets/TrendingProductsWidget';
+```
+
+### 2. Widget decomposition
+
+To assemble a trending products widget, we need the following components organized by atomic design tier.
+
+**Existing v1 (no work needed):**
+- [x] `Typography`
+- [x] `Link`
+- [x] `Box`
+
+**Atoms (to implement in `Atoms/`):**
+- [ ] `Carousel` — exists in v0 (MUI), reimplement in v1 with keen-slider.
+- [ ] `FavoriteButton` — exists in catalog, reimplement as presentational atom without MUI.
+- [ ] `Tooltip` — exists in v0 (MUI), reimplement with `@floating-ui/react`. (used by FavoriteButton)
+- [ ] `Popover` — exists in v0 (MUI), reimplement with `@floating-ui/react`. (used for pricing details)
+
+**Molecules (to implement in `Molecules/`):**
+- [ ] `RecommendationsProductCard` — exists in v0 (MUI), reimplement from catalog `RelatedProductCard`. Provisional name; likely becomes a variant of a future `ProductCard` atom.
+
+**No standalone `ImageWrapper` needed** — the image area is card-specific layout handled inside `RecommendationsProductCard`.
+
+### 3. Components Backfilling
+
+The normal Design System flow for a new component is:
+
+> Reco team creates Jira task → Designers create spec in Figma → Design System team reviews and implements → component is published → consumers use it
+
+This flow ensures quality and consistency but takes time. Waiting for it would block the widget migration.
+
+**Fast-track decision:** The Recommendations team will implement the required components directly inside the widget's `Atoms/` and `Molecules/` directories (see folder structure in section 1). These are local, widget-scoped implementations — not part of the Pigment public API yet.
+
+When the Design System team is ready to promote a component to the library, they can use the widget's implementation as a starting point rather than building from scratch.
+
+**Semver impact:**
+
+Widget code lives inside `packages/react`, so all changes increment Pigment's semver. **The Recommendations team must coordinate with the Design System team before merging breaking changes to the widget API. Non-breaking additions (new optional props, new components) can be merged independently under a minor bump.**
+
+**Responsibilities:**
+
+- **Recommendations team** — implements components in `Atoms/` and `Molecules/`, keeps them isolated inside the widget folder, creates a Jira task per component and labels it as tech debt.
+- **Design System team** — picks up the Jira tasks on their normal schedule, creates the Figma spec, and implements the official v1 component in `packages/react/src/components/`. Once the official component lands, the widget import is updated and the local copy removed.
+
+**Exit criteria (when a component graduates to the public library):**
+
+1. A Figma spec exists and has been reviewed by the Design System team.
+2. The official v1 implementation passes lint, type check, and unit tests.
+3. A Storybook story is published.
+4. The widget's internal import is updated to use the public component.
+5. The local `Atoms/<Name>/` or `Molecules/<Name>/` folder is deleted.
+6. The Jira tech-debt ticket is closed.
+
+**Tech debt tasks to create (one per component):**
+
+| Component | Tier | Jira label | Notes |
+|-----------|------|-----------|-------|
+| `Carousel` | Atom | `tech-debt`, `pigment-atom` | Replace local impl with official v1 once published |
+| `FavoriteButton` | Atom | `tech-debt`, `pigment-atom` | Presentational only; state stays in catalog |
+| `Tooltip` | Atom | `tech-debt`, `pigment-atom` | Needed by FavoriteButton |
+| `Popover` | Atom | `tech-debt`, `pigment-atom` | Needed for price breakdown |
+| `RecommendationsProductCard` | Molecule | `tech-debt`, `pigment-molecule` | Likely becomes a variant of a future `ProductCard` |
+
+### 4. Component Contracts
+
+> **Implementation requirement:** All components (atoms and molecules) must use `React.forwardRef`. This is a non-negotiable pattern in Pigment v1 (see `docs/ai/existing-patterns/components.md`). Each component must also set `displayName` for DevTools.
+
+---
+
+#### 4.1 Atoms
+
+Single-purpose primitives with no product-domain knowledge. Can be composed into molecules.
+
+##### ImageWrapper
+
+**Decision: no standalone `ImageWrapper` component needed.**
+
+The image area in `RecommendationsProductCard` is a `<div>` with `position: relative`, aspect-ratio padding, overflow hidden, and an inner absolutely-positioned `<img>`. This is card-specific layout, not a reusable atom. If the same pattern emerges across unrelated components, extract then.
+
+---
+
+##### Carousel
+
+The v0 `Carousel` is general-purpose (dots, thumbnails, navigator panel). `TrendingCarousel.jsx` skips it because it needs `'auto'` slide-width mode and dynamic `slidesPerView` computed from product count. The v1 is a focused reimplementation: keen-slider, no MUI, arrows only.
+
+```ts
+type CarouselProps = {
+  children: React.ReactNode;
+  slidesPerView?: number | 'auto';
+  spacing?: number;
+  loop?: boolean;
+  arrows?: boolean;
+  onPreviousClick?: () => void;
+  onNextClick?: () => void;
+  className?: string;
+  style?: React.CSSProperties;
+};
+```
+
+**Usage:**
+
+```tsx
+<Carousel slidesPerView={4} spacing={16} loop arrows>
+  {productCards}
+</Carousel>
+
+{/* With auto width — caller controls slide width via CSS */}
+<Carousel slidesPerView="auto" spacing={8}>
+  {productCards.map((card) => (
+    <div key={card.id} className={styles.slide}>
+      {card}
+    </div>
+  ))}
+</Carousel>
+```
+
+---
+
+#### 4.2 Molecules
+
+Components composed of atoms. Have product-domain knowledge and layout logic.
+
+##### RecommendationsProductCard
+
+> **Provisional name.** `RecommendationsProductCard` reflects the team context during the fast-track phase. Once the Design System team promotes this to the public library, it will likely be renamed to a variant of a future `ProductCard` atom (e.g. `ProductCard` with `variant="recommendation"`). The rename will be a breaking change and is tracked in the Jira tech-debt ticket.
+
+```ts
+type UnitPrice = {
+  quantity: number;
+  price: number; 
+};
+
+type RecommendationsProductCardProps = {
+  name: string;
+  linkHref: string;
+  imageSrc: string;
+  imageSrcSet?: string;
+  imageAlt?: string;
+  minQty: number;
+  ratingScore?: number;
+  ratingCount?: number;
+  defaultUnitPrices: UnitPrice[];
+  defaultQuoteQty: number;
+  onClick?: React.MouseEventHandler;
+  imageOverlay?: React.ReactNode;
+  children?: React.ReactNode;
+  className?: string;
+  style?: React.CSSProperties;
+};
+```
+
+**Usage:**
+
+```tsx
+// Basic
+<RecommendationsProductCard
+  name="Classic Unisex T-Shirt"
+  linkHref="/products/t-shirt"
+  imageSrc="https://cdn.customink.com/..."
+  minQty={12}
+  ratingScore={4.7}
+  ratingCount={312}
+  defaultUnitPrices={[{ quantity: 12, price: 8.99 }]}
+  defaultQuoteQty={12}
+  onClick={() => trackClick(product)}
+  imageOverlay={<FavoriteButton isFavorited={false} onToggle={handleToggle} />}
+/>
+
+// With extra content via children
+<RecommendationsProductCard
+  name="Classic Unisex T-Shirt"
+  linkHref="/products/t-shirt"
+  imageSrc="https://cdn.customink.com/..."
+  minQty={12}
+  defaultUnitPrices={[{ quantity: 12, price: 8.99 }]}
+  defaultQuoteQty={12}
+>
+  <AddToCartButton productId={product.styleId} />
+</RecommendationsProductCard>
+```
+
+---
+
+##### FavoriteButton
+
+- ![Trending products widget on Favorites page (WIP)](./rfc-assets/1-trending-products-widget-migration-img-5.png)
+
+State (`isFavorited`, `onToggle`) is owned by the consuming app's `FavoritesProvider`. The Pigment atom is purely presentational — renders `HeartIcon` / `HeartFilledIcon`, handles click and keyboard events, delegates upward.
+
+```ts
+type FavoriteButtonProps = {
+  isFavorited: boolean;
+  onToggle: (event: React.MouseEvent | React.KeyboardEvent) => void;
+  showTooltip?: boolean;
+  size?: 'sm' | 'md';
+  'aria-label'?: string;
+  className?: string;
+  style?: React.CSSProperties;
+};
+```
+
+**Usage:**
+
+```tsx
+// Standalone
+<FavoriteButton
+  isFavorited={isFavorited(product.styleId)}
+  onToggle={(e) => {
+    e.preventDefault();
+    e.stopPropagation();
+    toggleFavorite(product.styleId);
+  }}
+  showTooltip
+/>
+
+// Inside RecommendationsProductCard imageOverlay
+// Note: during fast-track phase, FavoriteButton is imported from the local Atoms/ directory,
+// not from the public package. Import path will change once the atom is promoted.
+<RecommendationsProductCard
+  {...cardProps}
+  imageOverlay={
+    <FavoriteButton
+      isFavorited={isFavorited(product.styleId)}
+      onToggle={(e) => { e.preventDefault(); toggleFavorite(product.styleId); }}
+    />
+  }
+/>
+```
+
+---
+
+##### Tooltip
+
+The v0 `Tooltip` is a one-line MUI passthrough. The v1 uses `@floating-ui/react` for positioning without MUI. Hover and focus triggered, renders in a portal.
+
+```ts
+type TooltipProps = {
+  title: React.ReactNode;
+  children: React.ReactElement;
+  placement?: 'top' | 'top-start' | 'top-end' | 'bottom' | 'bottom-start' | 'bottom-end' | 'left' | 'right';
+  arrow?: boolean;
+  open?: boolean;
+  defaultOpen?: boolean;
+  onOpenChange?: (open: boolean) => void;
+  className?: string;
+  style?: React.CSSProperties;
+};
+```
+
+**Usage:**
+
+```tsx
+<Tooltip title="Add to favorites" placement="bottom">
+  <button aria-label="Favorite">♡</button>
+</Tooltip>
+
+// Controlled
+<Tooltip title="Saved!" open={showConfirmation} placement="top">
+  <FavoriteButton isFavorited onToggle={handleToggle} />
+</Tooltip>
+```
+
+---
+
+##### Popover
+
+Used for pricing detail breakdown. Same `@floating-ui/react` stack as Tooltip, but click-triggered, interactive content, and dismissible on outside click / Escape.
+
+```ts
+type PopoverProps = {
+  trigger: React.ReactElement;
+  children: React.ReactNode;
+  placement?: 'top' | 'bottom' | 'left' | 'right';
+  open?: boolean;
+  defaultOpen?: boolean;
+  onOpenChange?: (open: boolean) => void;
+  className?: string;
+  style?: React.CSSProperties;
+};
+```
+
+**Usage:**
+
+```tsx
+<Popover
+  trigger={<button>See pricing details</button>}
+  placement="bottom"
+>
+  <PriceBreakdownTable prices={defaultUnitPrices} />
+</Popover>
+
+// Controlled
+<Popover
+  trigger={<span>{formattedPrice}</span>}
+  open={isPriceOpen}
+  onOpenChange={setIsPriceOpen}
+>
+  <PriceBreakdownTable prices={defaultUnitPrices} />
+</Popover>
+```
+
+---
+
+### Assembled widget
+
+`TrendingProductsWidget` composes the atoms. Data fetching stays in the consuming app — the widget accepts `products` + `isLoading` as props and is unaware of API endpoints.
+
+```ts
+type TrendingProduct = {
+  styleId: number;
+  name: string;
+  link: string;
+  imageSrc: string;
+  imageSrcSet?: string;
+  minQty: number;
+  ratingScore?: number;
+  ratingCount?: number;
+  defaultUnitPrices: { quantity: number; price: number }[];
+  defaultQuoteQty: number;
+  primaryCategoryId: number;
+};
+
+type TrendingProductsWidgetProps = {
+  products: TrendingProduct[];
+  isLoading?: boolean;
+  title?: string;
+  /**
+   * Called once when the widget scrolls into the viewport.
+   * Receives all loaded products so the consumer can build any analytics payload.
+   * @example (products) => gtag('event', 'view_item_list', { items: products.map(...) })
+   */
+  onWidgetViewed?: () => void;
+  /**
+   * Called when an individual product card enters the viewport.
+   * `index` is the 0-based position in the products array.
+   */
+  onCardViewed?: (product: TrendingProduct, index: number) => void;
+  /**
+   * Called when a product card is clicked.
+   * `index` is the 0-based position in the products array.
+   * @example (product, index) => gtag('event', 'select_item', { item_id: product.styleId, index })
+   */
+  onCardClicked?: (product: TrendingProduct, index: number) => void;
+  renderFavoriteButton?: (product: TrendingProduct) => React.ReactNode;
+  renderCardContent?: (product: TrendingProduct) => React.ReactNode;
+  /**
+   * Rendered below the carousel. Intended for supplemental content such as a
+   * "View all" link. Not rendered during the loading state.
+   */
+  children?: React.ReactNode;
+  className?: string;
+  style?: React.CSSProperties;
+};
+```
+
+Responsive `slidesPerView` logic (preserved from `TrendingCarousel.jsx`):
+
+| Breakpoint | Products ≥ threshold | `slidesPerView` | spacing |
+|------------|----------------------|-----------------|---------|
+| Mobile | ≥ 3 | 1.6 | 8px |
+| Mobile | < 3 | `'auto'` | 8px |
+| Desktop | ≥ 5 | 4 | 16px |
+| Desktop | < 5 | `'auto'` | 16px |
+
+Arrow visibility: arrows are shown only when **all three** conditions are true: `arrows` prop is `true` AND `!isMobile` AND `slidesPerView !== 'auto'`. On mobile, arrows are never rendered regardless of the `arrows` prop. Loading state renders 4-card shimmer skeleton. Returns `null` when `products` is empty.
+
+**Usage in catalog (after migration):**
+
+```tsx
+// catalog: TrendingCarousel.jsx
+// During fast-track: atoms are imported from the widget's local Atoms/ directory.
+// Once atoms are promoted to the public API, imports switch to '@customink/pigment-react'.
+import { TrendingProductsWidget } from '@customink/pigment-react';
+import { FavoriteButton } from '@customink/pigment-react/widgets/RecommendationsWidgets/TrendingProductsWidget/Atoms';
+import FavoritesProvider, { PageType } from 'features/favorites/FavoritesProvider';
+import { useFavorites } from 'features/favorites/FavoritesProvider';
+import useTrendingProductsWrapper from 'hooks/queries/useTrendingProductsWrapper';
+
+function TrendingCarouselInner({ categoryId, title, onProductClick }) {
+  const { isLoading, products } = useTrendingProductsWrapper({ categoryId });
+  const { isFavorited, toggleFavorite } = useFavorites();
+
+  return (
+    <TrendingProductsWidget
+      products={products}
+      isLoading={isLoading}
+      title={title}
+      onWidgetViewed={(products) =>
+        gtag('event', 'view_item_list', {
+          item_list_id: 'trending_products',
+          item_list_name: title,
+        })
+      }
+      onCardClicked={(product, index) =>
+        gtag('event', 'select_item', {
+          item_list_id: 'trending_products',
+          item_list_name: title,
+          item_id: String(product.styleId),
+          item_name: product.name,
+          index,
+        })
+      }
+      renderFavoriteButton={(product) => (
+        <FavoriteButton
+          isFavorited={isFavorited(product.styleId)}
+          onToggle={(e) => {
+            e.preventDefault();
+            e.stopPropagation();
+            toggleFavorite(product.styleId, { productId: product.styleId, source: 'rec_card', widgetType: 'trending' });
+          }}
+        />
+      )}

