import {
  Box,
  Card,
  CardContent,
  Stack,
  Typography
} from '@customink/pigment-react';
import {semantics} from '@customink/design-tokens';
import {useMobileBreakpoint} from '@customink/pigment-react/lib/utils/useBreakpoint';
import React from 'react';
import ProductCardPriceDetails from '../../features/products/components/ProductCard/components/ProductCardPriceDetails/ProductCardPriceDetails';
import ProductCardRating from '../../features/products/components/ProductCard/components/ProductCardRating';
import {processImageUrl, processSrcSet} from 'utils/addYDHToImageLink';
import {searchParams} from 'src/utils/url';
import FavoriteButton from '../../features/favorites/FavoriteButton';

const ProductDetailsCard = ({
  cardContentSx = {},
  categories = [],
  defaultQuoteQty,
  defaultUnitPrices,
  generalComments,
  imageSrc,
  imageSrcSet,
  linkHref,
  minQty,
  name,
  onClick,
  primaryCategoryId,
  productId,
  ratingCount,
  ratingScore,
  showFavoritesIcon = true,
  sx = {},
  widgetType
}) => {
  const isMobile = useMobileBreakpoint();
  const useNoMinimum =
    searchParams().get('quote_qty') === 'min' &&
    minQty === 1 &&
    defaultUnitPrices.find((price) => price.quantity === 1);

  const imageUrl = processImageUrl(imageSrc);
  const imageSetUrl = processSrcSet(imageSrcSet);
  const ratingCountNumber = Number(
    ratingCount.replace(/[()]/g, '').split(' ')[0]
  );
  const ratingScoreNumber = Number(ratingScore);

  return (
    <Card
      sx={{display: 'flex', flexDirection: 'column', height: '100%', ...sx}}
      aria-label={`View details for ${name}`}
      onClick={onClick}>
      <a href={linkHref}>
        <Box
          className="rpc-image-wrapper"
          sx={{
            '&:before': {
              boxShadow: '0px 0px 60px 24px #f5f5f5 inset',
              content: '""',
              inset: 0,
              mixBlendMode: 'darken',
              position: 'absolute',
              zIndex: 2
            },
            height: {md: 'unset !important', sm: '9.5rem'},
            objectFit: 'cover',
            overflow: 'hidden',
            paddingTop: {md: '100%', sm: '6.5rem'},
            position: 'relative',
            width: {md: '100%', sm: '10.1rem'}
          }}>
          <Box
            component="img"
            sx={{
              height: '100%',
              left: '50%',
              position: 'absolute',
              top: '50%',
              transform: 'translate(-50%, -50%)'
            }}
            src={imageUrl}
            srcSet={imageSetUrl}
            alt={name}
          />
          {showFavoritesIcon && (
            <FavoriteButton
              styleId={productId}
              primaryCategoryId={primaryCategoryId}
              categories={categories}
              source="rec_card"
              widgetType={widgetType}
              sx={{
                top: '0.5rem',
                right: '0.5rem',
                zIndex: 3
              }}
            />
          )}
        </Box>
      </a>
      <CardContent
        aria-label={`View details for ${name}`}
        sx={{
          display: 'flex',
          flex: '1',
          flexDirection: 'column',
          gap: '0.3125rem',
          height: '100%',
          justifyContent: {md: 'flex-start', sm: 'center'},
          mt: 0,
          padding: {md: '0.8125rem 1rem !important', sm: '0.5rem'},
          width: '100%',
          ...cardContentSx
        }}>
        <a href={linkHref}>
          <Typography
            data-testid="reco-product-name"
            sx={{
              color: semantics.light.neutral.text.primary,
              display: '-webkit-box',
              fontSize: {md: '0.875rem', sm: '0.8125rem'},
              fontWeight: 700,
              letterSpacing: 0,
              lineHeight: '125%',
              maxHeight: {md: '2.2rem !important', sm: '2rem !important'},
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              WebkitBoxOrient: 'vertical',
              WebkitLineClamp: 2
            }}
            title={name}>
            {name}
          </Typography>
        </a>
        {ratingCountNumber > 0 && ratingScoreNumber > 0 && (
          <Stack
            direction="row"
            gap="0.5rem"
            alignItems="center"
            height="1.25rem">
            <ProductCardRating
              count={ratingCountNumber}
              score={ratingScoreNumber}
              generalComments={generalComments}
              name={name}
            />
          </Stack>
        )}
        <ProductCardPriceDetails
          defaultUnitPrices={defaultUnitPrices}
          productId={productId}
          quantity={useNoMinimum ? 1 : defaultQuoteQty}
          minQty={minQty}
          name={name}
          frontColor={1}
          backColor={0}
          isMobile={isMobile}
          hasSinglesEnabledColors={false}
          hasDirtyQuoteQuantity={false}
          specialty={false}
          productColors={[]}
          primaryCategoryId={primaryCategoryId}
        />
        <Box
          sx={{
            display: 'flex',
            flexDirection: 'row',
            lineHeight: '1.25',
            mt: '0.0625rem',
            width: '100%'
          }}>
          <Typography
            data-testid="reco-product-minimum-quantity"
            sx={{
              color: semantics.light.neutral.text.primary,
              fontSize: '0.8125rem'
            }}>
            {minQty === 1 ? 'No Minimum' : `Minimum ${minQty}`}
          </Typography>
        </Box>
      </CardContent>
    </Card>
  );
};

export default ProductDetailsCard;

