     4→  HeartFilledIcon,
     5→  Tooltip
     6→} from '@customink/pigment-react';
     7→import {semantics} from '@customink/design-tokens';
     8→import React, {useMemo} from 'react';
     9→import {useFavorites} from './FavoritesProvider';
    10→import {SxProps} from '@mui/system';
    11→
    12→interface FavoriteButtonProps {
    13→  styleId: number;
    14→  sx?: SxProps;
    15→  showTooltip?: boolean;
    16→  primaryCategoryId: number | null;
    17→  categories: Category[];
    18→  containerSize?: string | number;
    19→  height?: string | number;
    20→  width?: string | number;
    21→  testId?: string;
    22→  source?: string;
    23→  widgetType?: string;
    24→}
    25→
    26→interface Category {
    27→  id: number;
    28→  name: string;
    29→}
    30→
    31→export default function FavoriteButton({
    32→  styleId,
    33→  sx = {},
    34→  showTooltip = false,
    35→  primaryCategoryId,
    36→  categories,
    37→  containerSize = '2.125rem',
    38→  height,
    39→  width,
    40→  testId = 'product-card-favorites-button',
    41→  source,
    42→  widgetType
    43→}: FavoriteButtonProps) {
    44→  const {isFavorited, toggleFavorite} = useFavorites();
    45→  const favorited = isFavorited(styleId);
    46→
    47→  const primaryCategoryName = useMemo(
    48→    () =>
    49→      categories.find((category: Category) => category.id === primaryCategoryId)
    50→        ?.name,
    51→    [categories, primaryCategoryId]
    52→  );
    53→
    54→  const handleClick = (event: React.MouseEvent<HTMLDivElement>) => {
    55→    event.preventDefault();
    56→    event.stopPropagation();
    57→    const rect = event.currentTarget.getBoundingClientRect();
    58→    void toggleFavorite(styleId, {
    59→      position: {top: rect.top, left: rect.right},
    60→      productCategory: primaryCategoryName,
    61→      productId: styleId,
    62→      source,
    63→      widgetType
    64→    });
    65→  };
    66→
    67→  const handleKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
    68→    if (event.key === 'Enter' || event.key === ' ') {
    69→      event.preventDefault();
    70→      event.stopPropagation();
    71→      const rect = event.currentTarget.getBoundingClientRect();
    72→      void toggleFavorite(styleId, {
    73→        position: {top: rect.top, left: rect.right},
    74→        productCategory: primaryCategoryName,
    75→        productId: styleId,
    76→        source,
    77→        widgetType
    78→      });
    79→    }
    80→  };
    81→
    82→  const tooltipTitle = favorited ? 'Remove from favorites' : 'Add to favorites';
    83→
    84→  const iconSize = {
    85→    width: width ?? '1.5rem',
    86→    height: height ?? '1.5rem'
    87→  };
    88→
    89→  const button = (
    90→    <Box
