import {
  Box,
  HeartIcon,
  HeartFilledIcon,
  Tooltip
} from '@customink/pigment-react';
import {semantics} from '@customink/design-tokens';
import React, {useMemo} from 'react';
import {useFavorites} from './FavoritesProvider';
import {SxProps} from '@mui/system';

interface FavoriteButtonProps {
  styleId: number;
  sx?: SxProps;
  showTooltip?: boolean;
  primaryCategoryId: number | null;
  categories: Category[];
  containerSize?: string | number;
  height?: string | number;
  width?: string | number;
  testId?: string;
  source?: string;
  widgetType?: string;
}

interface Category {
  id: number;
  name: string;
}

export default function FavoriteButton({
  styleId,
  sx = {},
  showTooltip = false,
  primaryCategoryId,
  categories,
  containerSize = '2.125rem',
  height,
  width,
  testId = 'product-card-favorites-button',
  source,
  widgetType
}: FavoriteButtonProps) {
  const {isFavorited, toggleFavorite} = useFavorites();
  const favorited = isFavorited(styleId);

  const primaryCategoryName = useMemo(
    () =>
      categories.find((category: Category) => category.id === primaryCategoryId)
        ?.name,
    [categories, primaryCategoryId]
  );

  const handleClick = (event: React.MouseEvent<HTMLDivElement>) => {
    event.preventDefault();
    event.stopPropagation();
    const rect = event.currentTarget.getBoundingClientRect();
    void toggleFavorite(styleId, {
      position: {top: rect.top, left: rect.right},
      productCategory: primaryCategoryName,
      productId: styleId,
      source,
      widgetType
    });
  };

  const handleKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      event.stopPropagation();
      const rect = event.currentTarget.getBoundingClientRect();
      void toggleFavorite(styleId, {
        position: {top: rect.top, left: rect.right},
        productCategory: primaryCategoryName,
        productId: styleId,
        source,
        widgetType
      });
    }
  };

  const tooltipTitle = favorited ? 'Remove from favorites' : 'Add to favorites';

  const iconSize = {
    width: width ?? '1.5rem',
    height: height ?? '1.5rem'
  };

  const button = (
    <Box
      role="button"
      tabIndex={0}
      aria-label={tooltipTitle}
      aria-pressed={favorited}
      data-testid={testId}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      sx={{
        position: 'absolute',
        cursor: 'pointer',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        width: containerSize,
        height: containerSize,
        padding: 0,
        margin: 0,
        backgroundColor: semantics.light.neutral.background.primary,
        borderRadius: '50%',
        boxShadow: '0 2px 8px rgba(0, 0, 0, 0.15)',
        transition: 'all 0.2s ease-in-out',
        '&:hover': {
          transform: 'scale(1.1)',
          boxShadow: '0 4px 12px rgba(0, 0, 0, 0.25)'
        },
        ...(!favorited && {
          '&:hover svg path': {
            fill: semantics.light.partnership.background.subtleHover,
            stroke: semantics.light.partnership.border.default,
            transition: 'fill 0.2s ease-in-out, stroke 0.2s ease-in-out'
          }
        }),
        ...sx
      }}>
      {favorited ? (
        <HeartFilledIcon
          sx={{
            color: semantics.light.partnership.icon.default,
            ...iconSize
          }}
        />
      ) : (
        <HeartIcon
          sx={{
            color: semantics.light.partnership.border.default,
            ...iconSize
          }}
        />
      )}
    </Box>
  );

  if (showTooltip) {
    return (
      <Tooltip title={tooltipTitle} placement="bottom" arrow>
        {button}
      </Tooltip>
    );
  }

  return button;
}

