import {Box, Link} from '@customink/pigment-react';
import {useRollbar} from '@rollbar/react';
import PropTypes from 'prop-types';
import React, {useCallback, useEffect, useMemo, useRef, useState} from 'react';
import {
  unbundledPriceEligibleByCategories,
  unbundledPriceSortEligible
} from 'utils/abTests/unbundledPriceTest';
import useProductCardPrice from '../../hooks/useProductCardPrice';
import ProductCardPriceDetailDialog from './ProductCardPriceDetailDialog';
import ProductCardPriceDetailsContent from './ProductCardPriceDetailsContent';
import ProductCardPricePopover from './ProductCardPricePopover';
import ProductCardRegularPrice from './ProductCardRegularPrice';
import PromoDiscountPrice from './PromoDiscountPrice/PromoDiscountPrice';
import BlankPrice from './BlankPrice';

export default function ProductCardPriceDetails({
  backColor,
  categories = [],
  categoryId,
  defaultUnitPrices,
  frontColor,
  hasDirtyQuoteQuantity = false,
  hasSinglesEnabledColors,
  isMobile,
  minQty,
  name,
  productColors,
  productId,
  quantity,
  specialty
}) {
  const rollbar = useRollbar();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isPopoverOpen, setIsPopoverOpen] = useState(false);
  const anchorRef = useRef(null);
  const closeTimeoutRef = useRef(null);
  const openTimeoutRef = useRef(null);

  const {
    localizedPrice,
    localizedRegularPrice,
    localizedBlankPrice,
    price,
    regularPrice
  } = useProductCardPrice({
    backColor,
    defaultUnitPrices,
    frontColor,
    hasDirtyQuoteQuantity,
    productId,
    quantity
  });

  const isUnbundledPriceEligible =
    unbundledPriceSortEligible(categoryId) ||
    unbundledPriceEligibleByCategories(categories);

  useEffect(() => {
    if (isUnbundledPriceEligible && !localizedBlankPrice) {
      rollbar.warning(
        'Blank price missing for unbundled price eligible product',
        {productId, categoryId}
      );
    }
  }, [
    isUnbundledPriceEligible,
    localizedBlankPrice,
    rollbar,
    productId,
    categoryId
  ]);

  const hasAlgoliaDiscount =
    regularPrice != null &&
    price != null &&
    Number(regularPrice) > Number(price);

  const shouldShowDiscount = hasAlgoliaDiscount;

  // Clean up timeouts on unmount
  useEffect(() => {
    return () => {
      if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
      if (openTimeoutRef.current) clearTimeout(openTimeoutRef.current);
    };
  }, []);

  const firePricingDetailsTag = useCallback(() => {
    window.dataLayer.push({
      event: 'interaction',
      interaction_action: 'pricing details',
      interaction_category: 'product listings page',
      interaction_label: name
    });
  }, [name]);

  const quatableMinQty = useMemo(() => {
    return (
      productColors?.find((col) => productId === col.id)?.min_qty || minQty
    );
  }, [minQty, productColors, productId]);

  const handleMouseEnter = useCallback(() => {
    if (!isMobile) {
      if (closeTimeoutRef.current) {
        clearTimeout(closeTimeoutRef.current);
      }
      if (openTimeoutRef.current) {
        clearTimeout(openTimeoutRef.current);
      }
      openTimeoutRef.current = setTimeout(() => {
        firePricingDetailsTag();
        setIsPopoverOpen(true);
      }, 100);
    }
  }, [firePricingDetailsTag, isMobile]);

  const handleMouseLeave = useCallback(() => {
    if (!isMobile) {
      if (openTimeoutRef.current) {
        clearTimeout(openTimeoutRef.current);
      }
      closeTimeoutRef.current = setTimeout(() => {
        setIsPopoverOpen(false);
      }, 100);
    }
  }, [isMobile]);

  const handleClick = (event) => {
    event.preventDefault();
    event.stopPropagation();
    if (isMobile) {
      firePricingDetailsTag();
      setIsModalOpen(true);
    }
  };

  if (!localizedPrice && !(isUnbundledPriceEligible && localizedBlankPrice)) {
    return null;
  }

  return (
    <Box
      display="flex"
      data-testid="product-price-details"
      flexDirection={isMobile ? 'column' : 'row'}
      alignItems={isMobile ? 'flex-start' : 'center'}
      justifyContent={isMobile ? 'center' : 'flex-start'}
      flexWrap={isMobile ? 'nowrap' : 'wrap'}
      lineHeight={1.25}
      onClick={(e) => e.stopPropagation()}
      gap="0.125rem 0.5rem">
      {isUnbundledPriceEligible && localizedBlankPrice ? (
        <BlankPrice price={localizedBlankPrice} />
      ) : shouldShowDiscount ? (
        <Box sx={{flexBasis: '100%'}}>
          <PromoDiscountPrice
            discountedPrice={localizedPrice}
            originalPrice={hasAlgoliaDiscount ? localizedRegularPrice : null}
            price={price}
            quantity={quantity}
          />
        </Box>
      ) : (
        <ProductCardRegularPrice price={localizedPrice} quantity={quantity} />
      )}
      {!(isUnbundledPriceEligible && localizedBlankPrice) && (
        <>
          <Link
            component="span"
            sx={{
              fontSize: '0.75rem',
              fontWeight: '500'
            }}
            ref={anchorRef}
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
            onClick={handleClick}>
            Pricing Details
          </Link>
          <Box>
            {isMobile && (
              <ProductCardPriceDetailDialog
                title={name}
                productId={productId}
                open={isModalOpen}
                onClose={() => setIsModalOpen(false)}>
                <ProductCardPriceDetailsContent
                  backColor={backColor}
                  frontColor={frontColor}
                  minQty={quatableMinQty}
                  productId={productId}
                  quantity={quantity}
                  hasSinglesEnabledColors={hasSinglesEnabledColors}
                  specialty={specialty}
                />
              </ProductCardPriceDetailDialog>
            )}
            {!isMobile && (
              <ProductCardPricePopover
                productId={productId}
                anchorEl={anchorRef.current}
                open={isPopoverOpen}
                onMouseEnter={handleMouseEnter}
                onMouseLeave={handleMouseLeave}>
                <ProductCardPriceDetailsContent
                  backColor={backColor}
                  frontColor={frontColor}
                  minQty={quatableMinQty}
                  productId={productId}
                  quantity={quantity}
                  hasSinglesEnabledColors={hasSinglesEnabledColors}
                  specialty={specialty}
                />
              </ProductCardPricePopover>
            )}
          </Box>
        </>
      )}
    </Box>
  );
}

ProductCardPriceDetails.propTypes = {
  backColor: PropTypes.number.isRequired,
  categories: PropTypes.arrayOf(PropTypes.object),
  categoryId: PropTypes.number,
  defaultUnitPrices: PropTypes.arrayOf(PropTypes.object).isRequired,
  frontColor: PropTypes.number.isRequired,
  hasSinglesEnabledColors: PropTypes.bool.isRequired,
  isMobile: PropTypes.bool.isRequired,
  minQty: PropTypes.number.isRequired,
  name: PropTypes.string.isRequired,
  productColors: PropTypes.arrayOf(PropTypes.object).isRequired,
  productId: PropTypes.number.isRequired,
  quantity: PropTypes.number.isRequired,
  specialty: PropTypes.bool.isRequired
};

