import {semantics} from '@customink/design-tokens';
import {styled} from '@customink/pigment-react/lib/themeCustomink';
import {Box, Popper} from '@mui/material';
import PropTypes from 'prop-types';
import React, {useState} from 'react';

const StyledPopper = styled(Popper)({
  '& .price-details--arrow': {
    '&:before': {
      borderStyle: 'solid',
      content: '""',
      display: 'block',
      height: 0,
      width: 0
    },
    position: 'absolute'
  },
  '&:before': {
    background: 'transparent',
    content: '""',
    height: '0.5rem',
    left: 0,
    position: 'absolute',
    right: 0,
    top: '-0.5rem'
  },
  '&[data-popper-placement*="bottom"] .price-details--arrow': {
    '&:before': {
      borderColor: `transparent transparent ${semantics.light.neutral.background.primary} transparent`,
      borderWidth: '0 0.5rem 0.5rem 0.5rem'
    },
    marginTop: '-0.5rem',
    top: 0
  },
  '&[data-popper-placement*="top"] .price-details--arrow': {
    '&:before': {
      borderColor: `${semantics.light.neutral.background.primary} transparent transparent transparent`,
      borderWidth: '0.5rem 0.5rem 0 0.5rem'
    },
    bottom: 0,
    marginBottom: '-0.5rem'
  },
  backgroundColor: semantics.light.neutral.background.primary,
  borderRadius: '0.5rem',
  boxShadow: '0 0 1rem rgba(0, 0, 0, 0.1)',
  padding: '1rem',
  zIndex: 10
});

export default function ProductCardPricePopover({
  anchorEl,
  children,
  onMouseEnter,
  onMouseLeave,
  open,
  productId
}) {
  const [arrowRef, setArrowRef] = useState(null);

  return (
    <StyledPopper
      id={`price-details-${productId}`}
      data-testid={`product-price-details-popover-${productId}`}
      open={open}
      anchorEl={anchorEl}
      placement="bottom"
      modifiers={[
        {
          enabled: true,
          name: 'arrow',
          options: {
            element: arrowRef
          }
        },
        {
          name: 'offset',
          options: {
            offset: [0, 8]
          }
        }
      ]}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}>
      <Box className="price-details--arrow" ref={setArrowRef} />
      {children}
    </StyledPopper>
  );
}

ProductCardPricePopover.propTypes = {
  anchorEl: PropTypes.object,
  children: PropTypes.node.isRequired,
  onMouseEnter: PropTypes.func.isRequired,
  onMouseLeave: PropTypes.func.isRequired,
  open: PropTypes.bool.isRequired,
  productId: PropTypes.number.isRequired
};

import {semantics} from '@customink/design-tokens';
import {Skeleton, Stack, Typography} from '@customink/pigment-react';
import {styled} from '@customink/pigment-react/lib/themeCustomink';
import {Table, TableBody, TableCell, TableHead, TableRow} from '@mui/material';
import PropTypes from 'prop-types';
import React from 'react';
import useProductCardPriceDetails from '../../hooks/useProductCardPriceDetails';

const StrippedTableRow = styled(TableRow)({
  '&:nth-of-type(odd)': {
    backgroundColor: semantics.light.neutral.background.subtle
  }
});

const StyledTableCell = styled(TableCell)({
  border: 'none',
  fontWeight: 700,
  height: '1rem',
  paddingBottom: 0.5,
  paddingTop: 0.5
});

export default function ProductCardPriceDetailsContent({
  backColor,
  frontColor,
  hasSinglesEnabledColors,
  minQty,
  productId,
  quantity,
  specialty
}) {
  const {isError, isLoading, priceDetailsData, quotableQuantities} =
    useProductCardPriceDetails(
      productId,
      minQty,
      hasSinglesEnabledColors,
      specialty,
      frontColor,
      backColor,
      quantity
    );

  // TODO: Validate copy for this error message and format with UX team
  if (isError) {
    return (
      <Typography>
        Error fetching price details, please re-open this dialog.
      </Typography>
    );
  }

  return (
    <Stack spacing={1} data-testid="product-price-details-content">
      <Stack spacing={1}>
        <Typography data-testid="product-price-details-content-title">
          For a {Math.max(frontColor, backColor)}-color, {backColor > 0 ? 2 : 1}
          -sided design:
        </Typography>
        <Table data-testid="product-price-details-content-table">
          <TableHead>
            <TableRow sx={{border: 'none'}}>
              <StyledTableCell data-testid="product-price-details-content-table-header-quantity">
                Quantity
              </StyledTableCell>
              <StyledTableCell data-testid="product-price-details-content-table-header-price-per-item">
                Price Per Item
              </StyledTableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {quotableQuantities.map((qty, index) => (
              <StrippedTableRow
                key={`price-details-${qty}`}
                data-testid="product-price-details-content-table-row">
                <TableCell
                  variant="head"
                  sx={{border: 'none', paddingY: 0.5}}
                  data-testid="product-price-details-content-table-cell-quantity">
                  {qty}
                  {index === 0 && ' (minimum)'}
                </TableCell>
                <TableCell
                  variant="head"
                  sx={{border: 'none', paddingY: 0.5}}
                  data-testid="product-price-details-content-table-cell-price-per-item">
                  {isLoading && (
                    <Skeleton
                      width="3rem"
                      data-testid="product-price-details-content-table-cell-price-per-item-skeleton"
                    />
                  )}
                  {!isLoading &&
                    priceDetailsData?.[qty] &&
                    `$${priceDetailsData[qty]}`}
                  {!isLoading && !priceDetailsData?.[qty] && '---'}
                </TableCell>
              </StrippedTableRow>
            ))}
          </TableBody>
        </Table>
      </Stack>
      <Stack data-testid="product-price-details-content-all-inclusive-pricing-includes">
        <Typography>All-inclusive pricing includes</Typography>
        <ul>
          <li>
            <Typography>
              <strong>FREE</strong> delivery
            </Typography>
          </li>
          <li>
            <Typography>
              <strong>FREE</strong> artwork review
            </Typography>
          </li>
          <li>
            <Typography>
              <strong>FREE</strong> artwork setup
            </Typography>
          </li>
        </ul>
      </Stack>
    </Stack>
  );
}

ProductCardPriceDetailsContent.propTypes = {
  backColor: PropTypes.number,
  frontColor: PropTypes.number,
  hasSinglesEnabledColors: PropTypes.bool,
  minQty: PropTypes.number,
  productId: PropTypes.number,
  quantity: PropTypes.number,
  specialty: PropTypes.bool
};

