/*
 * PostCSS showcase: this file exists to verify that @custom-media
 * from Pigment's shared breakpoints.css works in the extensions package.
 * postcss-custom-media resolves --md-up at build time.
 */

.banner {
  background: var(--partnership-background-bold);
  border-radius: var(--radius-default);
}

@media (--md-up) {
  .banner {
    background: linear-gradient(135deg, var(--partnership-background-bold), var(--interactive-background-bold));
  }
}

.text {
  color: var(--partnership-text-onFill);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  text-align: center;
}

@media (--md-up) {
  .text {
    white-space: normal;
    text-overflow: clip;
    overflow: visible;
    text-align: unset;
  }
}

