import React, { useCallback, useEffect, useRef, useState } from 'react';
import 'keen-slider/keen-slider.min.css';
import { useKeenSlider } from 'keen-slider/react';
import useResizeObserver from '@react-hook/resize-observer';
import { KeenSliderInstance } from 'keen-slider';
import styles from './Carousel.module.css';

export type CarouselProps = {
  /**
   * Show prev/next navigation arrows.
   * Arrows are automatically hidden when there is only 1 slide.
   * @default true
   */
  arrows?: boolean;

  /**
   * Position of arrows relative to the slider area.
   * @default 'inside'
   */
  arrowPosition?: 'inside' | 'outside';

  /**
   * Horizontal offset of arrows from the slider edge.
   * Only effective when `arrowPosition='outside'`.
   * Accepts a number (interpreted as pixels) or a CSS string value.
   * @default 40
   */
  arrowOffset?: string | number;

  /**
   * Show dot navigation below the slider.
   * Dots are hidden when `thumbnails` are provided.
   * @default true
   */
  dots?: boolean;

  /**
   * Enable lazy loading. Slides outside the visible window are replaced
   * with a placeholder until scrolled into view.
   * @default false
   */
  lazy?: boolean;

  /**
   * Number of additional offscreen slides to pre-load.
   * Only effective when `lazy=true`.
   * @default 1
   */
  lazyOffset?: number;

  /**
   * Allow slide navigation to wrap from last slide to first (and vice versa).
   * @default true
   */
  loop?: boolean;

  /**
   * Position of the thumbnail navigator when `thumbnails` are provided.
   * @default 'left'
   */
  navigatorSide?: 'left' | 'bottom';

  /**
   * Background color of the slider area.
   * @default 'white'
   */
  sliderBg?: 'white' | 'gray' | 'transparent';

  /**
   * Height of the slider area.
   * @default '350px'
   */
  sliderHeight?: string;

  /**
   * Inline style applied to the slider area `<div>` (excludes the thumbnail navigator).
   */
  sliderStyle?: React.CSSProperties;

  /**
   * Controls the origin of the slides within the slider viewport.
   * When `undefined`, the origin is auto-calculated: `'auto'` when `slidesPerView > 1`, `'center'` otherwise.
   * @default undefined
   */
  sliderOrigin?: 'auto' | 'center';

  /**
   * Array of slide content elements (usually images). Required.
   */
  slides: React.ReactElement[];

  /**
   * Number of slides visible simultaneously.
   * @default 1
   */
  slidesPerView?: number;

  /**
   * Spacing in pixels between adjacent slides.
   * @default 0
   */
  slidesSpacing?: number;

  /**
   * Array of thumbnail image elements for the thumbnail navigator.
   * When provided, dot navigation is hidden.
   */
  thumbnails?: React.ReactElement[];

  /**
   * Size of thumbnail items.
   * @default 'medium'
   */
  thumbSize?: 'small' | 'medium';

  /**
   * Called when the keen-slider instance is created.
   * Provides access to the KeenSliderInstance for programmatic control.
   */
  onCreated?: (slider: KeenSliderInstance) => void;
} & React.ComponentPropsWithoutRef<'div'>;

/**
 * Carousel component for displaying ordered sequences of slides with
 * thumbnail navigation, dot navigation, and prev/next arrow controls.
 * Built on keen-slider for touch/drag sliding and loop support.
 */
export const Carousel = React.forwardRef<HTMLDivElement, CarouselProps>(
  (
    {
      arrows = true,
      arrowPosition = 'inside',
      arrowOffset = 40,
      dots = true,
      lazy = false,
      lazyOffset = 1,
      loop = true,
      navigatorSide = 'left',
      sliderBg = 'white',
      sliderHeight = '350px',
      sliderStyle,
      sliderOrigin,
      slides,
      slidesPerView = 1,
      slidesSpacing = 0,
      thumbnails,
      thumbSize = 'medium',
      onCreated,
      className,
      ...restProps
    },
    ref,
  ) => {
    const [loaded, setLoaded] = useState<boolean[]>([]);
    const [currentSlide, setCurrentSlide] = useState(0);

    const origin = sliderOrigin ?? (slidesPerView > 1 ? 'auto' : 'center');

    const [keenSliderCallbackRef, instanceRef] = useKeenSlider<HTMLDivElement>({
      initial: 0,
      loop,
      slides: {
        origin,
        perView: slidesPerView,
        spacing: slidesSpacing,
      },
      animationEnded(slider) {
        setCurrentSlide(slider.track.details.rel);
      },
      slideChanged(slider) {
        setCurrentSlide(slider.track.details.rel);
      },
      created: onCreated,
    });

    /*
     * Resize keen-slider when the bounding div is resized.
     * keen-slider automatically listens for window resize, but needs manual
     * updates when layout changes independently of the window.
     * boundingBoxRef is a RefObject (has .current) required by useResizeObserver.
     * keenSliderCallbackRef is a callback ref (function only, no .current).
     */
    const boundingBoxRef = useRef<HTMLDivElement>(null);
    useResizeObserver(boundingBoxRef, () => instanceRef.current?.update());

    useEffect(() => {
      const newLoaded = [...loaded];
      newLoaded[currentSlide] = true;
      for (let i = 1; i < slidesPerView + lazyOffset; i++) {
        newLoaded[(currentSlide - i + slides.length) % slides.length] = true;
        newLoaded[(currentSlide + i + slides.length) % slides.length] = true;
      }
      setLoaded(newLoaded);
      // This dependency array is intentionally non-exhaustive — matches v0 behavior.
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentSlide]);

    const hasThumbs = !!thumbnails?.length;
    const showArrows = slides.length >= 2 && arrows;
    const cssArrowOffset = typeof arrowOffset === 'number' ? `${arrowOffset}px` : arrowOffset;

    // Calculate slider width based on thumbnail navigator presence and size
    const sliderWidth = (() => {
      if (!hasThumbs || navigatorSide === 'bottom') return '100%';
      const thumbSizeMap: Record<'small' | 'medium', number> = { medium: 56, small: 48 };
      const gutter = 16;
      return `calc(100% - ${thumbSizeMap[thumbSize] + gutter}px)`;
    })();

    const sliderBgClass = {
      white: styles.sliderBgWhite,
      gray: styles.sliderBgGray,
      transparent: styles.sliderBgTransparent,
    }[sliderBg];

    const rootClassNames = [styles.root, navigatorSide === 'left' ? styles.navigatorLeft : styles.navigatorBottom, className]
      .filter(Boolean)
      .join(' ');

    const handlePrev = useCallback(
      (e: React.MouseEvent) => {
        e.stopPropagation();
        instanceRef.current?.prev();
      },
      [instanceRef],
    );

    const handleNext = useCallback(
      (e: React.MouseEvent) => {
        e.stopPropagation();
        instanceRef.current?.next();
      },
      [instanceRef],
    );

    const handleMoveToIdx = useCallback(
      (e: React.MouseEvent<HTMLButtonElement>) => {
        instanceRef.current?.moveToIdx(Number(e.currentTarget.dataset.index));
      },
      [instanceRef],
    );

    return (
      <div ref={ref} className={rootClassNames} {...restProps}>
        <div
          ref={boundingBoxRef}
          className={[styles.slider, sliderBgClass].filter(Boolean).join(' ')}
          style={{ height: sliderHeight, width: sliderWidth, ...sliderStyle }}
        >
          {showArrows ? (
            <div className={styles.arrowContainer}>
              {!!instanceRef.current && (
                <>
                  <button
                    type="button"
                    aria-label="Previous slide"
                    // "arrow left" kept as literal classes for Playwright test selectors
                    className={[styles.arrow, arrowPosition === 'inside' ? styles.arrowInside : undefined, 'arrow left']
                      .filter(Boolean)
                      .join(' ')}
                    disabled={!loop && currentSlide === 0}
                    style={arrowPosition === 'outside' ? { position: 'absolute', left: `-${cssArrowOffset}` } : undefined}
                    onClick={handlePrev}
                  >
                    <svg
                      width={24}
                      height={24}
                      viewBox="0 0 24 24"
                      fill="none"
                      xmlns="http://www.w3.org/2000/svg"
                      aria-hidden="true"
                      style={{ transform: 'scale(-1, 1)' }}
                    >
                      <path
                        fillRule="evenodd"
                        clipRule="evenodd"
                        d="M8.29289 5.70711C7.90237 5.31658 7.90237 4.68342 8.29289 4.29289C8.68342 3.90237 9.31658 3.90237 9.70711 4.29289L16.7071 11.2929C17.0976 11.6834 17.0976 12.3166 16.7071 12.7071L9.70711 19.7071C9.31658 20.0976 8.68342 20.0976 8.29289 19.7071C7.90237 19.3166 7.90237 18.6834 8.29289 18.2929L14.5858 12L8.29289 5.70711Z"
                        fill="currentColor"
                      />
                    </svg>
                  </button>

                  <button
                    type="button"
                    aria-label="Next slide"
                    // "arrow right" kept as literal classes for Playwright test selectors
                    className={[styles.arrow, arrowPosition === 'inside' ? styles.arrowInside : undefined, 'arrow right']
                      .filter(Boolean)
                      .join(' ')}
                    disabled={!loop && currentSlide >= slides.length - slidesPerView}
                    style={arrowPosition === 'outside' ? { position: 'absolute', right: `-${cssArrowOffset}` } : undefined}
                    onClick={handleNext}
                  >
                    <svg
                      width={24}
                      height={24}
                      viewBox="0 0 24 24"
                      fill="none"
                      xmlns="http://www.w3.org/2000/svg"
                      aria-hidden="true"
                    >
                      <path
                        fillRule="evenodd"
                        clipRule="evenodd"
                        d="M8.29289 5.70711C7.90237 5.31658 7.90237 4.68342 8.29289 4.29289C8.68342 3.90237 9.31658 3.90237 9.70711 4.29289L16.7071 11.2929C17.0976 11.6834 17.0976 12.3166 16.7071 12.7071L9.70711 19.7071C9.31658 20.0976 8.68342 20.0976 8.29289 19.7071C7.90237 19.3166 7.90237 18.6834 8.29289 18.2929L14.5858 12L8.29289 5.70711Z"
                        fill="currentColor"
                      />
                    </svg>
                  </button>
                </>
              )}
            </div>
          ) : null}

          <div ref={keenSliderCallbackRef} className={`keen-slider ${styles.keenSlider}`}>
            {slides.map((slide, i) => (
              <div key={i} className={`keen-slider__slide ${styles.slide}`}>
                {lazy && !loaded[i] ? <div className={styles.lazyPlaceholder} /> : slide}
              </div>
            ))}
          </div>

          {!hasThumbs && dots && slides.length > 1 ? (
            <div className={styles.dotsContainer}>
              {Array.from({ length: slides.length }, (_, i) => (
                <button
                  key={i}
                  type="button"
                  aria-label={`Go to slide ${i + 1}`}
                  aria-current={currentSlide === i ? 'true' : undefined}
                  className={[styles.dot, currentSlide === i ? styles.dotActive : undefined].filter(Boolean).join(' ')}
                  data-index={i}
                  onClick={handleMoveToIdx}
                />
              ))}
            </div>
          ) : null}
        </div>

        {hasThumbs && !!instanceRef.current ? (
          <div className={styles.thumbnailsContainer}>
            <div
              className={[
                styles.thumbnails,
                navigatorSide === 'left' ? styles.thumbnailsLeft : styles.thumbnailsBottom,
              ].join(' ')}
              style={navigatorSide === 'left' ? { maxHeight: sliderHeight } : undefined}
            >
              {thumbnails.map((thumbnailEl, i) => (
                <button
                  key={i}
                  type="button"
                  aria-pressed={currentSlide === i}
                  // "thumbnail" kept as literal class for Playwright test selectors
                  className={[
                    styles.thumbnail,
                    thumbSize === 'medium' ? styles.thumbnailMedium : styles.thumbnailSmall,
                    currentSlide === i ? styles.thumbnailSelected : undefined,
                    'thumbnail',
                  ]
                    .filter(Boolean)
                    .join(' ')}
                  data-index={i}
                  onClick={handleMoveToIdx}
                >
                  {thumbnailEl}
                </button>
              ))}
            </div>
          </div>
        ) : null}
      </div>
    );
  },
);

