/* Root container */
.root {
  display: flex;
  width: 100%;
  height: max-content;
}

.navigatorLeft {
  flex-direction: row-reverse;
}

.navigatorBottom {
  flex-direction: column;
}

/* Slider area */
.slider {
  position: relative;
  overflow: visible;
}

/* Slider backgrounds */
.sliderBgWhite {
  background-color: var(--neutral-background-primary);
}

.sliderBgGray {
  background-color: #f4f4f4; /* TODO: verify - not in spec; closest v3: --neutral-background-subtle */
}

.sliderBgTransparent {
  background-color: transparent;
}

/* keen-slider container */
.keenSlider {
  height: 100%;
  /* Ensure adjacent slides are clipped even if keen-slider/keen-slider.min.css
     is not injected in this rendering context (e.g. Next.js App Router). */
  overflow: hidden;
}

/* Slide items (added alongside keen-slider__slide class) */
.slide {
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: grab;
}

/* Force slide content (images, etc.) to fill the slider height, matching v0 behavior.
   Without this, images render at natural size and may overflow the slide container. */
.slide > * {
  height: 100%;
}

/* Lazy loading placeholder */
.lazyPlaceholder {
  width: 100%;
  height: 100%;
  background-color: var(--neutral-background-subtle);
}

/* Arrow container — absolute overlay, pointer-events disabled so slides are draggable through it */
.arrowContainer {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  display: flex;
  justify-content: space-between;
  align-items: center;
  pointer-events: none;
}

/* Arrow button */
.arrow {
  pointer-events: auto;
  width: 32px; /* --size-tappable-stingy */
  height: 32px;
  border-radius: 50%; /* --radius-round */
  background-color: #ffffff; /* --neutral-background-primary */
  box-shadow: 0px 4px 8px rgba(0, 0, 0, 0.08); /* raw value — no token */
  border: none;
  padding: 0;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1;
  color: #4a4a4a; /* --primitives-color-neutral-gray700 — no semantic match; needs Figma verification */
  flex-shrink: 0;
}

.arrowInside {
  margin: 0 8px;
}

.arrow:not(:disabled):hover {
  background-color: #f3f3f3; /* TODO: verify - not in spec; closest v3: --primitives-color-neutral-gray100 */
}

.arrow:not(:disabled):active {
  background-color: rgba(24, 24, 24, 0.1); /* TODO: verify - not in spec; closest v3: --interactive-background-weak */
}

.arrow:disabled {
  background-color: transparent;
  box-shadow: none;
  cursor: default;
  color: #c6c6c6; /* TODO: verify - not in spec; closest v3: --interactive-icon-disabled */
}

.arrow:focus-visible {
  outline: 2px solid var(--interactive-border-focus);
  outline-offset: 2px;
}

/* Dots container */
.dotsContainer {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 20px 0;
  display: flex;
  justify-content: center;
}

/* Dot button */
.dot {
  border: none;
  background: transparent;
  width: 8px;
  height: 8px;
  padding: 4px;
  /* box-sizing content-box prevents padding from collapsing the content area */
  box-sizing: content-box;
  cursor: pointer;
  display: inline-flex;
}

.dot::after {
  content: '';
  background: #ffffff;
  opacity: 0.6;
  width: 8px;
  height: 8px;
  border-radius: 61px;
  display: block;
}

.dot:hover::after {
  opacity: 1;
}

.dotActive {
  cursor: default;
}

.dotActive::after {
  opacity: 1;
  background: #4a4a4a; /* TODO: verify - not in spec; needs Figma verification */
}

/* Thumbnails navigator */
.thumbnailsContainer {
  display: flex;
  justify-content: center;
}

.thumbnails {
  display: flex;
  gap: 8px; /* --space-detailLayout-xl */
}

.thumbnailsLeft {
  flex-direction: column;
  margin-right: 16px; /* --space-componentLayout-md */
  overflow-y: auto;
}

.thumbnailsBottom {
  margin-top: 16px; /* --space-componentLayout-md */
  justify-content: flex-start;
  overflow-x: auto;
}

/* Thumbnail button */
.thumbnail {
  position: relative;
  display: flex;
  justify-content: center;
  box-sizing: border-box;
  overflow: hidden;
  background-color: #ffffff; /* --neutral-background-primary */
  border-radius: 4px; /* --radius-sm */
  flex-shrink: 0;
  cursor: pointer;
  border: none;
  padding: 0;
}

/* ::before overlay creates the border inside the image (avoids overlap with image content) */
.thumbnail::before {
  border-radius: 4px;
  border: 1px solid #f4f4f4; /* TODO: verify - not in spec; closest v3: --neutral-border-weak */
  transition: border 0.1s ease-out;
  position: absolute;
  content: ' ';
  top: 0;
  bottom: 0;
  right: 0;
  left: 0;
  mix-blend-mode: darken;
  box-shadow: inset 0px 0px 8px 4px #f4f4f4; /* decorative — raw value */
}

.thumbnail:hover::before {
  border: 1px solid #c6c6c6; /* TODO: verify - not in spec; needs Figma verification */
}

.thumbnailSelected {
  cursor: default;
}

.thumbnailSelected::before {
  border: 1px solid #181818; /* --primitives-color-neutral-gray990 — no semantic match; needs Figma verification */
}

.thumbnailMedium {
  width: 56px;
  height: 56px;
}

.thumbnailMedium > * {
  width: 56px;
  object-fit: contain;
}

.thumbnailSmall {
  width: 48px;
  height: 48px;
}

.thumbnailSmall > * {
  width: 48px;
  object-fit: contain;
}

