import React, { useCallback, useRef, useState } from 'react';
import styles from './Tooltip.module.css';

export interface TooltipProps {
  /** Tooltip label content */
  title: React.ReactNode;
  /** The element that triggers the tooltip */
  children: React.ReactElement;
  /** Preferred placement relative to the trigger.
   * @default 'bottom'
   */
  placement?: 'top' | 'bottom';
  /** Show an arrow pointing to the trigger.
   * @default true
   */
  arrow?: boolean;
}

/**
 * Tooltip — pure CSS/React, no external positioning library.
 *
 * Shows on hover and keyboard focus of the child element.
 * Intended for small labels (single line).
 */
export const Tooltip = React.forwardRef<HTMLSpanElement, TooltipProps>(
  function Tooltip({ title, children, placement = 'bottom', arrow = true }, ref) {
    const [visible, setVisible] = useState(false);
    const hideTimeout = useRef<ReturnType<typeof setTimeout> | null>(null);

    const show = useCallback(() => {
      if (hideTimeout.current) clearTimeout(hideTimeout.current);
      setVisible(true);
    }, []);

    const hide = useCallback(() => {
      // Small delay prevents flicker when moving between trigger and tooltip
      hideTimeout.current = setTimeout(() => setVisible(false), 80);
    }, []);

    const child = React.Children.only(children);

    const trigger = React.cloneElement(child, {
      onMouseEnter: (e: React.MouseEvent) => {
        show();
        child.props.onMouseEnter?.(e);
      },
      onMouseLeave: (e: React.MouseEvent) => {
        hide();
        child.props.onMouseLeave?.(e);
      },
      onFocus: (e: React.FocusEvent) => {
        show();
        child.props.onFocus?.(e);
      },
      onBlur: (e: React.FocusEvent) => {
        hide();
        child.props.onBlur?.(e);
      },
    });

    const tooltipClass = [
      styles.tooltip,
      placement === 'top' ? styles.top : styles.bottom,
      visible ? styles.visible : undefined,
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <span ref={ref} className={styles.wrapper}>
        {trigger}
        <span role="tooltip" className={tooltipClass} aria-hidden={!visible}>
          {title}
          {arrow && <span className={styles.arrow} aria-hidden="true" />}
        </span>
      </span>
    );
  },
);

Tooltip.displayName = 'Tooltip';

