import React, { useCallback } from 'react';
import { Tooltip } from '../Tooltip';
import styles from './FavoriteButton.module.css';

export interface FavoriteButtonProps {
  /** Whether the product is currently favorited */
  isFavorited: boolean;
  /** Called when the button is clicked or activated via keyboard */
  onToggle: (event: React.MouseEvent | React.KeyboardEvent) => void;
  /** Show a tooltip label on hover/focus */
  showTooltip?: boolean;
  /** Button size
   * @default 'md'
   */
  size?: 'sm' | 'md';
  /** Override accessible label (defaults to "Add to favorites" / "Remove from favorites") */
  'aria-label'?: string;
  className?: string;
  style?: React.CSSProperties;
}

const HEART_OUTLINE_PATH =
  'M4 9C4 12.1242 7.06067 15.9005 12.0057 19.1333C16.9507 15.9005 20 12.2045 20 9C20 6.79086 18.2091 5 16 5C15.0005 5 14.0631 5.36538 13.3338 6.01806L12.3715 6.87932C12.1663 7.06298 11.8364 7.06548 11.6285 6.87932L10.6662 6.01806C9.93695 5.36538 8.99954 5 8 5C5.79086 5 4 6.79086 4 9ZM12 4.52779C13.0615 3.57771 14.4633 3 16 3C19.3137 3 22 5.68629 22 9C22 13.8362 16.994 18.5 12.4246 21.2363C12.1924 21.3809 11.8112 21.3828 11.5783 21.2383C6.97858 18.511 2 13.8365 2 9C2 5.68629 4.68629 3 8 3C9.53671 3 10.9385 3.57771 12 4.52779Z';

const HEART_FILLED_PATH =
  'M12 4.52779C13.0615 3.57771 14.4633 3 16 3C19.3137 3 22 5.68629 22 9C22 13.8362 16.994 18.5 12.4246 21.2363C12.1924 21.3809 11.8112 21.3828 11.5783 21.2383C6.97858 18.511 2 13.8365 2 9C2 5.68629 4.68629 3 8 3C9.53671 3 10.9385 3.57771 12 4.52779Z';

/**
 * FavoriteButton — purely presentational.
 *
 * State (isFavorited, onToggle) is owned by the consuming app.
 * Intended to be rendered via the `renderFavoriteButton` prop of TrendingProductsWidget.
 */
export const FavoriteButton = React.forwardRef<HTMLDivElement, FavoriteButtonProps>(
  function FavoriteButton(
    {
      isFavorited,
      onToggle,
      showTooltip = false,
      size = 'md',
      'aria-label': ariaLabel,
      className,
      style,
    },
    ref,
  ) {
    const label = ariaLabel ?? (isFavorited ? 'Remove from favorites' : 'Add to favorites');

    const handleKeyDown = useCallback(
      (e: React.KeyboardEvent<HTMLDivElement>) => {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          e.stopPropagation();
          onToggle(e);
        }
      },
      [onToggle],
    );

    const handleClick = useCallback(
      (e: React.MouseEvent<HTMLDivElement>) => {
        e.preventDefault();
        e.stopPropagation();
        onToggle(e);
      },
      [onToggle],
    );

    const rootClass = [
      styles.root,
      size === 'sm' ? styles.sm : styles.md,
      isFavorited ? styles.favorited : undefined,
      className,
    ]
      .filter(Boolean)
      .join(' ');

    const iconSize = size === 'sm' ? 18 : 24;

    const button = (
      <div
        ref={ref}
        role="button"
        tabIndex={0}
        aria-label={label}
        aria-pressed={isFavorited}
        className={rootClass}
        style={style}
        onClick={handleClick}
        onKeyDown={handleKeyDown}
      >
        <svg
          width={iconSize}
          height={iconSize}
          viewBox="0 0 24 24"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
          className={styles.icon}
        >
          <path
            fillRule="evenodd"
            clipRule="evenodd"
            d={isFavorited ? HEART_FILLED_PATH : HEART_OUTLINE_PATH}
            fill="currentColor"
          />
        </svg>
      </div>
    );

    if (showTooltip) {
      return (
        <Tooltip title={label} placement="bottom">
          {button}
        </Tooltip>
      );
    }

    return button;
  },
);

FavoriteButton.displayName = 'FavoriteButton';

