        onKeyDown={handleKeyDown}
      >
        <svg
          width={iconSize}
          height={iconSize}
          viewBox="0 0 24 24"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
          className={styles.icon}
        >
          <path
            fillRule="evenodd"
            clipRule="evenodd"
            d={isFavorited ? HEART_FILLED_PATH : HEART_OUTLINE_PATH}
            fill="currentColor"
          />
        </svg>
      </div>
    );

    if (showTooltip) {
      return (
        <Tooltip title={label} placement="bottom">
          {button}
        </Tooltip>
      );
    }

    return button;
  },
);

