// If the score is less than 1, set it to 1. This is according to a Google structured markup schema requirement.
// The assumed default worst rating is 1.0, so if the score is less than 1, we set it to 1.
// https://developers.google.com/search/docs/appearance/structured-data/review-snippet
function adjustMinimumScore(score) {
  if (score === undefined) {
    return undefined;
  }
  if (Number(score) < 1) {
    return 1;
  }
  return Number(score);
}

export function formatRatingScore(score) {
  return Number(adjustMinimumScore(score)).toFixed(1);
}

export function formatRatingCount(count) {
  if (count === undefined || Number.isNaN(count)) {
    return null;
  }

  const capLimit = 10000;
  const isCapped = count > capLimit;
  const cappedCount = isCapped ? capLimit : count;
  let formattedCount = cappedCount.toLocaleString();

  if (isCapped) {
    formattedCount += '+';
  }

  return `(${formattedCount})`;
}

export function generateStructuredDataRatingData(
  name,
  ratingCount,
  ratingScore,
  generalComments
) {
  const data = {
    '@context': 'https://schema.org',
    '@type': 'Product',
    aggregateRating: {
      '@type': 'AggregateRating',
      bestRating: '5',
      ratingCount: `${ratingCount}`,
      ratingValue: adjustMinimumScore(ratingScore)
    },
    description: generalComments,
    name
  };

  return JSON.stringify(data);
}

