export type UnitPrice = {
  quantity: number;
  price: number;
};

export type TrendingProduct = {
  styleId: number;
  name: string;
  link: string;
  imageSrc: string;
  imageSrcSet?: string;
  imageAlt?: string;
  minQty: number;
  ratingScore?: number;
  ratingCount?: number;
  defaultUnitPrices: UnitPrice[];
  defaultQuoteQty: number;
  primaryCategoryId: number;
};

export type TrendingProductsWidgetProps = {
  products: TrendingProduct[];
  /** @default false */
  isLoading?: boolean;
  /** @default 'Trending Products' */
  title?: string;
  /**
   * Fired once when the widget scrolls into the viewport.
   * Receives all loaded products so the caller can build any analytics payload.
   */
  onWidgetViewed?: (products: TrendingProduct[]) => void;
  /**
   * Fired when a product card is clicked.
   * `index` is the 0-based position in the products array.
   */
  onCardClicked?: (product: TrendingProduct, index: number) => void;
  /**
   * Render prop: inject a FavoriteButton from the consuming app.
   * Rendered as an absolute overlay in the top-right of the product image.
   * The consuming app owns favorites state and wraps the widget with FavoritesProvider.
   */
  renderFavoriteButton?: (product: TrendingProduct) => React.ReactNode;
  /**
   * Render prop: inject custom price display (e.g. ProductCardPriceDetails from catalog).
   * Falls back to a simple price derived from defaultUnitPrices when omitted.
   */
  renderPriceDetails?: (product: TrendingProduct) => React.ReactNode;
  /**
   * Rendered below the carousel. Intended for supplemental content such as a "View all" link.
   * Not rendered during the loading state.
   */
  children?: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
};

