import React, { useCallback, useEffect, useRef, useState } from 'react';
import 'keen-slider/keen-slider.min.css';
import { useKeenSlider } from 'keen-slider/react';
import useResizeObserver from '@react-hook/resize-observer';
import { Typography } from '@customink/pigment-react';
import type { TrendingProduct, TrendingProductsWidgetProps } from './types';
import { LoadingSkeleton } from './Atoms/LoadingSkeleton';
import { RecommendationsProductCard } from './Molecules/RecommendationsProductCard';
import styles from './TrendingProductsWidget.module.css';

const MOBILE_BREAKPOINT = 700; // px — matches --md-up in breakpoints.css

function useMobileBreakpoint(): boolean {
  const [isMobile, setIsMobile] = useState(
    () => typeof window !== 'undefined' && window.innerWidth < MOBILE_BREAKPOINT,
  );

  useEffect(() => {
    const mq = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);
    const handler = (e: MediaQueryListEvent) => setIsMobile(e.matches);
    setIsMobile(mq.matches);
    mq.addEventListener('change', handler);
    return () => mq.removeEventListener('change', handler);
  }, []);

  return isMobile;
}

function getSlidesConfig(
  productCount: number,
  isMobile: boolean,
): { perView: number | 'auto'; spacing: number } {
  if (isMobile) {
    return { perView: productCount >= 3 ? 1.6 : 'auto', spacing: 8 };
  }
  return { perView: productCount >= 5 ? 4 : 'auto', spacing: 16 };
}

/**
 * TrendingProductsWidget — assembled widget for the Recommendations team.
 *
 * Data fetching stays in the consuming app. The widget is unaware of API endpoints.
 * Wrap with FavoritesProvider in the consuming app and inject FavoriteButton
 * via the `renderFavoriteButton` render prop.
 */
export const TrendingProductsWidget = React.forwardRef<
  HTMLDivElement,
  TrendingProductsWidgetProps
>(function TrendingProductsWidget(
  {
    products,
    isLoading = false,
    title = 'Trending Products',
    onWidgetViewed,
    onCardClicked,
    renderFavoriteButton,
    renderPriceDetails,
    children,
    className,
    style,
  },
  ref,
) {
  const isMobile = useMobileBreakpoint();
  const { perView, spacing } = getSlidesConfig(products.length, isMobile);
  const isAutoWidth = perView === 'auto';
  const showArrows = !isAutoWidth && !isMobile;

  const widgetRef = useRef<HTMLDivElement>(null);
  const hasFiredViewEvent = useRef(false);

  const [keenRef, instanceRef] = useKeenSlider<HTMLDivElement>({
    loop: true,
    mode: 'snap',
    slides: isAutoWidth
      ? { perView: 'auto', spacing }
      : { perView, spacing },
  });

  // Merge external ref + keenRef into boundingBoxRef
  const boundingBoxRef = useRef<HTMLDivElement>(null);
  const mergedSliderRef = useCallback(
    (node: HTMLDivElement | null) => {
      (boundingBoxRef as React.MutableRefObject<HTMLDivElement | null>).current = node;
      keenRef(node);
    },
    [keenRef],
  );

  useResizeObserver(boundingBoxRef, () => instanceRef.current?.update());

  // Reinitialise keen-slider when layout-affecting props change
  useEffect(() => {
    instanceRef.current?.update({ loop: true, mode: 'snap',
      slides: isAutoWidth ? { perView: 'auto', spacing } : { perView, spacing },
    });
  }, [perView, spacing, isAutoWidth, instanceRef]);

  // Fire onWidgetViewed once when the widget scrolls into view
  useEffect(() => {
    const el = widgetRef.current;
    if (!el || products.length === 0 || hasFiredViewEvent.current) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting && !hasFiredViewEvent.current) {
            onWidgetViewed?.(products);
            hasFiredViewEvent.current = true;
          }
        });
      },
      { threshold: 0.1 },
    );

    observer.observe(el);
    return () => observer.disconnect();
  }, [products, onWidgetViewed]);

  const handlePrev = useCallback((e: React.MouseEvent) => {
    e.stopPropagation();
    instanceRef.current?.prev();
  }, [instanceRef]);

  const handleNext = useCallback((e: React.MouseEvent) => {
    e.stopPropagation();
    instanceRef.current?.next();
  }, [instanceRef]);

  if (isLoading) return <LoadingSkeleton />;
  if (products.length === 0) return null;

  const rootClass = [styles.root, className].filter(Boolean).join(' ');

  return (
    <div ref={ref} className={rootClass} style={style}>
      <div ref={widgetRef} className={styles.inner}>
        <div className={styles.header}>
          <Typography className={styles.title}>{title}</Typography>
        </div>

        <div className={styles.carouselContainer}>
          {showArrows && (
            <div className={styles.arrowContainer}>
              <button
                type="button"
                className={`${styles.arrow} ${styles.arrowLeft}`}
                onClick={handlePrev}
                aria-label="Previous products"
              >
                <svg width={20} height={20} viewBox="0 0 24 24" fill="none" aria-hidden="true">
                  <path
                    fillRule="evenodd"
                    clipRule="evenodd"
                    d="M8.29289 5.70711C7.90237 5.31658 7.90237 4.68342 8.29289 4.29289C8.68342 3.90237 9.31658 3.90237 9.70711 4.29289L16.7071 11.2929C17.0976 11.6834 17.0976 12.3166 16.7071 12.7071L9.70711 19.7071C9.31658 20.0976 8.68342 20.0976 8.29289 19.7071C7.90237 19.3166 7.90237 18.6834 8.29289 18.2929L14.5858 12L8.29289 5.70711Z"
                    fill="currentColor"
                    style={{ transform: 'scale(-1, 1)', transformOrigin: 'center' }}
                  />
                </svg>
              </button>
              <button
                type="button"
                className={`${styles.arrow} ${styles.arrowRight}`}
                onClick={handleNext}
                aria-label="Next products"
              >
                <svg width={20} height={20} viewBox="0 0 24 24" fill="none" aria-hidden="true">
                  <path
                    fillRule="evenodd"
                    clipRule="evenodd"
                    d="M8.29289 5.70711C7.90237 5.31658 7.90237 4.68342 8.29289 4.29289C8.68342 3.90237 9.31658 3.90237 9.70711 4.29289L16.7071 11.2929C17.0976 11.6834 17.0976 12.3166 16.7071 12.7071L9.70711 19.7071C9.31658 20.0976 8.68342 20.0976 8.29289 19.7071C7.90237 19.3166 7.90237 18.6834 8.29289 18.2929L14.5858 12L8.29289 5.70711Z"
                    fill="currentColor"
                  />
                </svg>
              </button>
            </div>
          )}

          <div ref={mergedSliderRef} className="keen-slider">
            {products.map((product, index) => (
              <div
                key={product.styleId}
                className={`keen-slider__slide${isAutoWidth ? ` ${styles.slideAutoWidth}` : ''}`}
              >
                <RecommendationsProductCard
                  name={product.name}
                  linkHref={product.link}
                  imageSrc={product.imageSrc}
                  imageSrcSet={product.imageSrcSet}
                  imageAlt={product.imageAlt}
                  minQty={product.minQty}
                  ratingScore={product.ratingScore}
                  ratingCount={product.ratingCount}
                  defaultUnitPrices={product.defaultUnitPrices}
                  defaultQuoteQty={product.defaultQuoteQty}
                  onClick={() => onCardClicked?.(product, index)}
                  imageOverlay={renderFavoriteButton?.(product)}
                  renderPriceDetails={renderPriceDetails ? () => renderPriceDetails(product) : undefined}
                />
              </div>
            ))}
          </div>
        </div>

        {children}
      </div>
    </div>
  );
});

TrendingProductsWidget.displayName = 'TrendingProductsWidget';

