.root {
  margin-top: 2.5rem;
  margin-bottom: 2.5rem;
  width: 100%;
}

.inner {
  width: 100%;
}

/* Header */
.header {
  margin-bottom: 0.28125rem;
  text-align: left;
}

@media (max-width: 699px) {
  .header {
    margin-bottom: 0.8125rem;
  }
}

.title {
  color: var(--neutral-text-primary);
  font-size: 1.5rem !important;
  font-weight: 700 !important;
  line-height: 1.25 !important;
}

/* Carousel container — wraps arrows + slider */
.carouselContainer {
  position: relative;
  display: flex;
  width: 100%;
  height: max-content;
}

/* Arrow overlay — sits over the slider, pointer-events: none so cards are still draggable */
.arrowContainer {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  display: flex;
  justify-content: space-between;
  align-items: center;
  pointer-events: none;
  z-index: 1;
}

.arrow {
  pointer-events: auto;
  width: 2rem;
  height: 2rem;
  border-radius: 50%;
  background-color: var(--neutral-background-primary);
  box-shadow: 0 0.25rem 0.5rem rgba(0, 0, 0, 0.08);
  border: none;
  padding: 0;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--neutral-icon-default);
  flex-shrink: 0;
  transition: background-color 0.15s ease;
  margin: 0 0.5rem;
}

.arrow:hover {
  background-color: var(--neutral-background-subtleOpaque);
}

.arrow:active {
  background-color: var(--neutral-background-subtle);
}

.arrow:focus-visible {
  outline: 2px solid var(--interactive-border-focus);
  outline-offset: 2px;
}

/* Slide — auto-width mode: caller controls width via CSS */
.slideAutoWidth {
  max-width: 19.25rem;
  width: 100%;
  margin-right: 1rem;
}

@media (max-width: 699px) {
  .slideAutoWidth {
    margin-right: 1rem;
  }
}

