import type { Meta, StoryObj } from '@storybook/react';
import { TrendingProductsWidget } from '@customink/pigment-extensions/reco';
import type { TrendingProduct } from '@customink/pigment-extensions/reco';

const meta: Meta<typeof TrendingProductsWidget> = {
  title: 'Extensions/Reco/TrendingProductsWidget',
  component: TrendingProductsWidget,
  parameters: {
    layout: 'padded',
  },
};

export default meta;
type Story = StoryObj<typeof TrendingProductsWidget>;

const makeProduct = (id: number, name: string): TrendingProduct => ({
  styleId: id,
  name,
  link: `/products/${id}`,
  imageSrc: `https://media.customink.com/images/products/${id}/colors/1/catalog.jpg`,
  minQty: 6,
  ratingScore: 4.5 + (id % 5) * 0.1,
  ratingCount: 100 + id * 13,
  defaultUnitPrices: [{ quantity: 6, price: 9.99 + id }],
  defaultQuoteQty: 6,
  primaryCategoryId: 1,
});

const PRODUCTS: TrendingProduct[] = [
  makeProduct(1, 'Classic Unisex T-Shirt'),
  makeProduct(2, 'Premium Hoodie'),
  makeProduct(3, 'Canvas Tote Bag'),
  makeProduct(4, 'Performance Polo'),
  makeProduct(5, 'Fleece Crewneck'),
  makeProduct(6, 'Long Sleeve Tee'),
];

const FEW_PRODUCTS: TrendingProduct[] = PRODUCTS.slice(0, 2);

export const Default: Story = {
  args: {
    products: PRODUCTS,
    title: 'Trending Products',
  },
};

export const Loading: Story = {
  args: {
    products: [],
    isLoading: true,
    title: 'Trending Products',
  },
};

export const FewProducts: Story = {
  name: 'Few Products (auto-width)',
  args: {
    products: FEW_PRODUCTS,
    title: 'Trending Products',
  },
};

export const WithFavoriteButton: Story = {
  args: {
    products: PRODUCTS,
    title: 'Trending Products',
    renderFavoriteButton: (product) => {
      // Simulate a stateful FavoriteButton — in production this comes from catalog's FavoritesProvider
      return (
        <button
          type="button"
          aria-label={`Favorite ${product.name}`}
          onClick={(e) => {
            e.preventDefault();
            e.stopPropagation();
          }}
          style={{
            position: 'absolute',
            top: '0.5rem',
            right: '0.5rem',
            width: '2.125rem',
            height: '2.125rem',
            borderRadius: '50%',
            border: 'none',
            background: 'white',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
            zIndex: 2,
          }}
        >
          ♡
        </button>
      );
    },
  },
};

export const Empty: Story = {
  args: {
    products: [],
    title: 'Trending Products',
  },
  parameters: {
    docs: {
      description: {
        story: 'Returns null when products array is empty.',
      },
    },
  },
};

