import type { TrendingProduct } from '../TrendingProductsWidget/types';
import { useTrendingProducts } from './useTrendingProducts';

const mockProduct: TrendingProduct = {
  styleId: 1,
  name: 'Classic Tee',
  link: '/products/classic-tee',
  imageSrc: 'https://example.com/tee.jpg',
  minQty: 6,
  defaultUnitPrices: [{ quantity: 6, price: 9.99 }],
  defaultQuoteQty: 12,
  primaryCategoryId: 42,
};

describe('useTrendingProducts', () => {
  it('returns isLoading=true initially and products=[] while fetching', () => {
    // fetcher never resolves within this tick
    const fetcher = jest.fn(() => new Promise<TrendingProduct[]>(() => {}));

    const { result } = renderHook(() => useTrendingProducts({ fetcher }));

    expect(result.current.isLoading).toBe(true);
    expect(result.current.products).toEqual([]);
    expect(result.current.isError).toBe(false);
  });

  it('returns products after fetcher resolves', async () => {
    const fetcher = jest.fn().mockResolvedValue([mockProduct]);

    const { result } = renderHook(() => useTrendingProducts({ fetcher }));

    await waitFor(() => expect(result.current.isLoading).toBe(false));

    expect(result.current.products).toEqual([mockProduct]);
    expect(result.current.isError).toBe(false);
  });

  it('returns isError=true and products=[] when fetcher rejects', async () => {
    const fetcher = jest.fn().mockRejectedValue(new Error('network error'));

    const { result } = renderHook(() => useTrendingProducts({ fetcher }));

    await waitFor(() => expect(result.current.isLoading).toBe(false));

    expect(result.current.isError).toBe(true);
    expect(result.current.products).toEqual([]);
  });

  it('does not call fetcher when enabled=false', () => {
    const fetcher = jest.fn().mockResolvedValue([mockProduct]);

    renderHook(() => useTrendingProducts({ fetcher, enabled: false }));

    expect(fetcher).not.toHaveBeenCalled();
  });

  it('calls fetcher when enabled changes from false to true', async () => {
    const fetcher = jest.fn().mockResolvedValue([mockProduct]);

    const { result, rerender } = renderHook(
      ({ enabled }: { enabled: boolean }) => useTrendingProducts({ fetcher, enabled }),
      { initialProps: { enabled: false } },
    );

    expect(fetcher).not.toHaveBeenCalled();

    rerender({ enabled: true });

    await waitFor(() => expect(result.current.isLoading).toBe(false));

    expect(fetcher).toHaveBeenCalledTimes(1);
    expect(result.current.products).toEqual([mockProduct]);
  });
});
